const skills = computed(() => copy.value.about.skills)
const themeToggleTitle = computed(() => (isDark.value ? copy.value.nav.themeLight : copy.value.nav.themeDark))
const localeOptions = computed(() => [
  { code: 'pt', short: 'PT', label: copy.value.localeNames.pt },
  { code: 'en', short: 'EN', label: copy.value.localeNames.en },
  { code: 'es', short: 'ES', label: copy.value.localeNames.es },
])

function toggleTheme() {
  isDark.value = !isDark.value
  if (import.meta.client) {
    localStorage.setItem('portfolio-theme', isDark.value ? 'dark' : 'light')
  }
}

function setLocale(locale) {
  currentLocale.value = locale in translations ? locale : 'pt'

  if (import.meta.client) {
    localStorage.setItem('portfolio-locale', currentLocale.value)
    document.documentElement.lang = currentLocale.value
  }
}

function detectLocale(language = '') {
  const locale = language.toLowerCase()

  if (locale.startsWith('en')) return 'en'
  if (locale.startsWith('es')) return 'es'

  return 'pt'
}

function scrollTo(id) {
  document.getElementById(id)?.scrollIntoView({ behavior: 'smooth' })
}
function onScroll() { isScrolled.value = window.scrollY > 40 }

